class UnionFind {
    constructor(size) {
        this.parent = Array.from({ length: size + 1 }, (_, i) => i);
        this.minNode = Array.from({ length: size + 1 }, (_, i) => i);
    }

    find(x) {
        while (this.parent[x] !== x) {
            this.parent[x] = this.parent[this.parent[x]];
            x = this.parent[x];
        }
        return x;
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);
        if (xRoot === yRoot) return;
        if (xRoot < yRoot) {
            this.parent[yRoot] = xRoot;
            this.minNode[xRoot] = Math.min(this.minNode[xRoot], this.minNode[yRoot]);
        } else {
            this.parent[xRoot] = yRoot;
            this.minNode[yRoot] = Math.min(this.minNode[xRoot], this.minNode[yRoot]);
        }
    }
}

function solve(c, connections, queries) {
    const uf = new UnionFind(c);
    for (const [u, v] of connections) {
        uf.union(u, v);
    }

    const online = Array(c + 1).fill(true);
    const res = [];

    for (const [type, x] of queries) {
        if (type === 1) {
            const root = uf.find(x);
            if (online[x]) {
                res.push(x);
            } else {
                let minOnline = Infinity;
                let found = false;
                for (let node = 1; node <= c; node++) {
                    if (uf.find(node) === root && online[node]) {
                        if (node < minOnline) {
                            minOnline = node;
                            found = true;
                        }
                    }
                }
                if (found) {
                    res.push(minOnline);
                } else {
                    res.push(-1);
                }
            }
        } else if (type === 2) {
            online[x] = false;
        }
    }
    return res;
}
